// 1. Acesso correto ao body do n8n
const body = items[0].json.body || {};

// O campo correto enviado pelo seu webhook é "Resumo"
const content = body.Resumo || ""; 

const extract = (regex) => {
    if (!content) return null;
    const match = content.match(regex);
    return match ? match[1].trim() : null;
};

// 2. Extração dos dados baseada no padrão do texto enviado
const tipo = extract(/Tipo:\s*(.*)/);
const leadRaw = extract(/Lead:\s*(.*)/);
const telefoneRaw = extract(/Telefone:\s*(.*)/);
const cidadeRaw = extract(/Cidade:\s*(.*)/) || "";
// Ajuste na regex de Situação para capturar até o fim ou até Contexto
const situacao = extract(/Situação:\s*([\s\S]*?)(?=\nContexto:|$)/) || "";
const contexto = extract(/Contexto:\s*([\s\S]*)/) || "";

// 3. Padronização do Telefone (Usa o campo Phone direto do body se o Regex falhar)
const phoneSource = body.Phone || telefoneRaw || "";
const digitsOnly = phoneSource.replace(/\D/g, '');
const phoneClean = digitsOnly ? `+${digitsOnly}` : null;

// 4. Lógica de Roteamento Inteligente
let whatsapp_destino = "553498912728"; // Fallback
let responsavel_nome = "Suporte Central";

const textoBusca = (situacao + " " + contexto).toLowerCase();
const cidadeNormalizada = cidadeRaw.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

if (textoBusca.includes("bruna") || cidadeNormalizada.includes("uberlandia")) {
    whatsapp_destino = "553498912728"; 
    responsavel_nome = "Bruna";
} else if (textoBusca.includes("maria") || cidadeNormalizada.includes("ituiutaba") || body.Responsavel === "Maria") {
    whatsapp_destino = "553497065870"; 
    responsavel_nome = "Maria";
}

// 5. Tratamento para SQL
const resumoBruto = `MOTIVO: ${tipo} | SITUAÇÃO: ${situacao} | CONTEXTO: ${contexto}`;
const resumoSQL = resumoBruto.replace(/'/g, "''"); 

return [{
    json: {
        tipo,
        lead_nome: leadRaw,
        phone_db: phoneClean,
        cidade: cidadeRaw,
        situacao,
        contexto,
        whatsapp_destino,
        responsavel_nome,
        resumo_final: resumoSQL
    }
}];

