const tipo = body.Tipo || "Não classificado";
const leadRaw = body.Nome || "Desconhecido";
const situacao = body.Resumo || "";
const contexto = body.Contexto || "";
const cidadeRaw = body.Cidade || "Não informada";

// 3. Padronização do Telefone
const phoneSource = body.Phone || "";
const digitsOnly = phoneSource.replace(/\D/g, '');
const phoneClean = digitsOnly ? `+${digitsOnly}` : "Não informado";
const linkWhatsApp = digitsOnly ? `https://wa.me/55${digitsOnly.replace(/^55/, '')}` : "";

// 4. Montagem da Mensagem para o Grupo
const mensagemGrupo = `🚨 *NOVO ACIONAMENTO - EQUIPE SUPORTE* 🚨\n\n` +
                      `*Tipo:* ${tipo}\n` +
                      `*Nome:* ${leadRaw}\n` +
                      `*Cidade:* ${cidadeRaw}\n` +
                      `*Contato:* ${phoneClean}\n\n` +
                      `*Situação:*\n_${situacao}_\n\n` +
                      `*Contexto Interno:*\n_${contexto}_\n\n` +
                      `*Link Rápido para Atendimento:*\n👉 ${linkWhatsApp}`;

// 5. Tratamento para SQL
const resumoBruto = `MOTIVO: ${tipo} | SITUAÇÃO: ${situacao} | CONTEXTO: ${contexto}`;
const resumoSQL = resumoBruto.replace(/'/g, "''");

// 6. Destino
const destino_grupo = "ID_DO_SEU_GRUPO@g.us";

return [{
    json: {
        tipo,
        lead_nome: leadRaw,
        phone_db: phoneClean,
        cidade: cidadeRaw,
        situacao,
        contexto,
        mensagem_whatsapp: mensagemGrupo,
